from collections import deque

def solve():
    input_data = sys.stdin.buffer.read().split()
    idx = 0
    t = int(input_data[idx]); idx += 1
    for _ in range(t):
        n, m = int(input_data[idx]), int(input_data[idx+1]); idx += 2
        grid = []
        lab = None
        for i in range(n):
            row = input_data[idx].decode(); idx += 1
            grid.append(list(row))
            for j in range(len(row)):
                if row[j] == 'L':
                    lab = (i, j)

        dirs = [(0,1),(1,0),(0,-1),(-1,0)]  # right, down, left, up

        good = [[False]*m for _ in range(n)]
        # bad_count[i][j][d] = number of free non-good neighbors in directions != d
        bad_count = [[[0]*4 for _ in range(m)] for _ in range(n)]

        for i in range(n):
            for j in range(m):
                if grid[i][j] == '#': continue
                for d in range(4):
                    cnt = 0
                    for d2 in range(4):
                        if d2 == d: continue
                        ni, nj = i+dirs[d2][0], j+dirs[d2][1]
                        if 0<=ni<n and 0<=nj<m and grid[ni][nj] != '#':
                            cnt += 1
                    bad_count[i][j][d] = cnt

        queue = deque()
        li, lj = lab
        good[li][lj] = True
        queue.append((li, lj))

        while queue:
            gi, gj = queue.popleft()
            for d2 in range(4):
                ci, cj = gi - dirs[d2][0], gj - dirs[d2][1]
                if 0<=ci<n and 0<=cj<m and grid[ci][cj] != '#' and not good[ci][cj]:
                    for d in range(4):
